package main

import (
    "database/sql"
    "net/http"
    "os/exec"
)

func handler(w http.ResponseWriter, r *http.Request, db *sql.DB) {
    cmd := r.FormValue("cmd")
    exec.Command("sh", "-c", cmd)
    name := r.URL.Query().Get("name")
    db.Query("select * from users where name=" + name)
}

func main() {
    http.ListenAndServe(":8080", nil)
}
